export function formatProof(proof) {
  return validateHexString(proof);
}
export function formatVk(vk) {
  if (typeof vk !== 'object' || vk === null || !('vkBytes' in vk)) {
    throw new Error('Invalid EZKL VK format: expected object with vkBytes property');
  }
  const vkBytes = validateHexString(vk.vkBytes);
  return {
    vkBytes
  };
}
export function formatPubs(pubs) {
  return pubs.map(validateHexString);
}
function validateHexString(input) {
  if (!input.startsWith('0x')) {
    throw new Error('Invalid format: string input must be 0x-prefixed.');
  }
  return input;
}